worked_example.final_code:
// BankAccount.java (class under test)
public class BankAccount {
    private final String id;
    private double balance;
    private boolean closed = false;

    public BankAccount(String id, double balance) { this.id = id; this.balance = balance; }
    public void deposit(double amount) { checkOpen(); check(amount > 0, "Amount must be positive"); balance += amount; }
    public void withdraw(double amount) {
        checkOpen(); check(amount > 0, "Amount must be positive");
        check(amount <= balance, "Insufficient funds: ₹" + balance + " available, ₹" + amount + " requested");
        balance -= amount;
    }
    public double getBalance() { checkOpen(); return balance; }
    public void close() { closed = true; }
    private void checkOpen() { if (closed) throw new IllegalStateException("Account is closed"); }
    private void check(boolean condition, String msg) { if (!condition) throw new IllegalArgumentException(msg); }
}

// BankAccountTest.java
import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

class BankAccountTest {
    BankAccount account;

    @BeforeEach void setUp() { account = new BankAccount("ACC-001", 1000.0); }

    @Test void newAccount_hasInitialBalance() { assertEquals(1000.0, account.getBalance()); }

    @Test void deposit_validAmount_increasesBalance() {
        account.deposit(500); assertEquals(1500.0, account.getBalance()); }

    @Test void withdraw_validAmount_decreasesBalance() {
        account.withdraw(300); assertEquals(700.0, account.getBalance()); }

    @Test void withdraw_insufficientFunds_throwsIllegalStateException() {
        IllegalStateException ex = assertThrows(IllegalStateException.class,
            () -> account.withdraw(2000));
        assertTrue(ex.getMessage().contains("Insufficient funds"));
    }

    @Test void deposit_negativeAmount_throwsIllegalArgumentException() {
        assertThrows(IllegalArgumentException.class, () -> account.deposit(-100));
    }

    @Test @DisplayName("Closed account throws on all operations")
    void closedAccount_anyOperation_throws() {
        account.close();
        assertAll(
            () -> assertThrows(IllegalStateException.class, () -> account.deposit(100)),
            () -> assertThrows(IllegalStateException.class, () -> account.withdraw(100)),
            () -> assertThrows(IllegalStateException.class, () -> account.getBalance())
        );
    }

    @Test @Disabled("Not yet implemented")
    void transfer_betweenAccounts_movesBalance() { }
}

